INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), '2sm', 9, 1, NULL, 'Andrew Murray em 2Sm 9:1', 'Na leitura de Andrew Murray, vemos a coerência doutrinária aplicada à vida cristã. 2 Samuel 9 evidencia providência divina na história do povo de Deus como eixo da vida do povo de Deus, com ênfase em amor fraternal. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Andrew Murray', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), '2sm', 10, 1, NULL, 'Orígenes em 2Sm 10:1', 'Orígenes interpreta este versículo a partir de a leitura cristológica e eclesial da passagem. Em 2 Samuel 10, Deus revela providência divina na história do povo de Deus de forma pastoral e transformadora, promovendo fidelidade na aliança. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Orígenes', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), '2sm', 11, 1, NULL, 'Richard Baxter em 2Sm 11:1', 'Richard Baxter destaca a piedade prática e a santificação do coração. Em 2 Samuel 11, o foco recai sobre providência divina na história do povo de Deus e chama a igreja para vida de oração. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Richard Baxter', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), '2sm', 12, 1, NULL, 'Charles Spurgeon em 2Sm 12:1', 'Charles Spurgeon interpreta este versículo a partir de a coerência doutrinária aplicada à vida cristã. Em 2 Samuel 12, Deus revela providência divina na história do povo de Deus de forma pastoral e transformadora, promovendo santidade prática. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Charles Spurgeon', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), '2sm', 13, 1, NULL, 'Jerônimo em 2Sm 13:1', 'Segundo Jerônimo, a leitura cristológica e eclesial da passagem ilumina o sentido deste texto. 2 Samuel 13 mostra que providência divina na história do povo de Deus sustenta a caminhada da fé, especialmente em obediência da fé. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Jerônimo', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), '2sm', 14, 1, NULL, 'John Owen em 2Sm 14:1', 'Na leitura de John Owen, vemos a piedade prática e a santificação do coração. 2 Samuel 14 evidencia providência divina na história do povo de Deus como eixo da vida do povo de Deus, com ênfase em adoração reverente. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'John Owen', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), '2sm', 15, 1, NULL, 'A. A. Hodge em 2Sm 15:1', 'Segundo A. A. Hodge, a coerência doutrinária aplicada à vida cristã ilumina o sentido deste texto. 2 Samuel 15 mostra que providência divina na história do povo de Deus sustenta a caminhada da fé, especialmente em amor fraternal. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'A. A. Hodge', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), '2sm', 16, 1, NULL, 'João Crisóstomo em 2Sm 16:1', 'João Crisóstomo destaca a leitura cristológica e eclesial da passagem. Em 2 Samuel 16, o foco recai sobre providência divina na história do povo de Deus e chama a igreja para fidelidade na aliança. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'João Crisóstomo', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), '2sm', 17, 1, NULL, 'Jonathan Edwards em 2Sm 17:1', 'Jonathan Edwards interpreta este versículo a partir de a piedade prática e a santificação do coração. Em 2 Samuel 17, Deus revela providência divina na história do povo de Deus de forma pastoral e transformadora, promovendo vida de oração. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Jonathan Edwards', 'commentary', '#2E8B57', NOW()),
